// src/components/CourseCard.jsx
import React from 'react';
import { Link } from 'react-router-dom';

const CourseCard = ({ course }) => {
  return (
    <div style={styles.card}>
      <div style={styles.cardIcon}>📚</div>
      <h3 style={styles.cardTitle}>{course.name}</h3>
      <p style={styles.cardBranch}>{course.branch} • Sem {course.semester}</p>
      
      <div style={styles.tagsContainer}>
        <span style={styles.tag}>Notes</span>
        <span style={styles.tag}>PYQs</span>
        <span style={styles.tag}>Syllabus</span>
      </div>
      
      <Link to={`/courses/${course.id}`}>
        <button style={styles.viewButton}>View Details →</button>
      </Link>
    </div>
  );
};

const styles = {
  card: {
    background: 'white',
    borderRadius: '15px',
    padding: '25px',
    boxShadow: '0 10px 30px rgba(0,0,0,0.1)',
    textAlign: 'center',
    transition: 'all 0.3s',
    border: '1px solid #e5e7eb',
    height: '100%',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'space-between'
  },
  cardIcon: {
    fontSize: '3rem',
    marginBottom: '1rem'
  },
  cardTitle: {
    fontSize: '1.3rem',
    fontWeight: 'bold',
    color: '#333',
    marginBottom: '0.5rem'
  },
  cardBranch: {
    color: '#666',
    marginBottom: '1rem',
    fontSize: '0.9rem'
  },
  tagsContainer: {
    display: 'flex',
    justifyContent: 'center',
    gap: '0.5rem',
    marginBottom: '1.5rem'
  },
  tag: {
    background: '#e0e7ff',
    color: '#4f46e5',
    padding: '5px 12px',
    borderRadius: '15px',
    fontSize: '0.8rem'
  },
  viewButton: {
    width: '100%',
    padding: '12px',
    background: 'linear-gradient(90deg, #4f46e5, #7c3aed)',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    fontWeight: 'bold',
    cursor: 'pointer',
    fontSize: '1rem',
    transition: 'all 0.3s'
  }
};

export default CourseCard;
